;(()=>{
  const mountedViews=new WeakSet();

  function randomizeView(view){
    if(!view || mountedViews.has(view)) return;
    mountedViews.add(view);

    const items=[...view.querySelectorAll('.floating-object')];
    if(!items.length) return;

    const positions=[];
    const heroIndex=Math.floor(Math.random()*items.length);

    function makePosition(isHero){
      const minDistance=isHero?18:12.5;
      for(let attempt=0;attempt<180;attempt++){
        const x=15+Math.random()*70;
        const y=12+Math.random()*74;
        const ok=positions.every(p=>Math.hypot((x-p.x)*1.16,y-p.y)>minDistance);
        if(ok){const pos={x,y};positions.push(pos);return pos;}
      }
      const pos={x:18+Math.random()*64,y:15+Math.random()*68};
      positions.push(pos);
      return pos;
    }

    items.forEach((el,i)=>{
      const isHero=i===heroIndex;
      const pos=makePosition(isHero);
      el.style.setProperty('--left',pos.x.toFixed(2)+'%');
      el.style.setProperty('--top',pos.y.toFixed(2)+'%');
      el.style.setProperty('--rotation',(Math.random()*38-19).toFixed(1)+'deg');
      el.style.setProperty('--object-scale',(isHero?1.42+Math.random()*.24:.72+Math.random()*.55).toFixed(2));
      el.style.setProperty('--breath',(5.4+Math.random()*4.2).toFixed(2)+'s');
      el.style.setProperty('--skew-x',(Math.random()*4-2).toFixed(2)+'deg');
      el.style.setProperty('--skew-y',(Math.random()*3-1.5).toFixed(2)+'deg');
      el.style.animationDelay=(-Math.random()*5).toFixed(2)+'s';
      if(isHero) el.dataset.hero='true'; else delete el.dataset.hero;
    });
  }

  function discover(root=document){
    if(root.nodeType===1 && root.matches?.('.objects-view')) randomizeView(root);
    root.querySelectorAll?.('.objects-view').forEach(randomizeView);
  }

  const observer=new MutationObserver(records=>{
    records.forEach(record=>record.addedNodes.forEach(node=>{
      if(node.nodeType===1) discover(node);
    }));
  });
  observer.observe(document.documentElement,{childList:true,subtree:true});
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded',()=>discover());
  else discover();
})();
